      <rect x="460" y="52" width="210" height="26" rx="4" fill="rgba(167,139,250,.22)" stroke="#a78bfa"/>
      <text x="565" y="70" fill="#a78bfa" font-size="13" font-weight="700" text-anchor="middle">Parallel with BALs (Glamsterdam)</text>
