      <line x1="20" y1="174" x2="680" y2="174" stroke="rgba(255,255,255,.08)"/>
      <text x="20" y="208" fill="#a1a1aa" font-size="13">Main bottleneck</text>
      <text x="335" y="208" fill="#e4e4e7" font-size="13" text-anchor="middle">Single-threaded execution</text>
      <text x="565" y="208" fill="#e4e4e7" font-size="13" text-anchor="middle">Shifts to bandwidth / state</text>
      <line x1="20" y1="222" x2="680" y2="222" stroke="rgba(255,255,255,.08)"/>
